    log::info!("Testing denial box structure");
    let pattern_match = PatternMatch::mock_critical();
    let output = render_denial_box(&pattern_match);

    log::debug!("Rendered output:\n{}", output);

    assert!(output.contains("BLOCKED"), "Must contain BLOCKED header");
    assert!(output.contains(&pattern_match.command), "Must contain command");
    assert!(output.contains(&pattern_match.pattern_id), "Must contain pattern ID");
    assert!(output.contains("Severity"), "Must contain severity");
    assert!(output.contains("Why"), "Must contain explanation");
