    log::info!("Testing long command wrapping");
    let long_cmd = "very_long_command ".repeat(20);
    let pattern_match = PatternMatch::with_command(&long_cmd);
    let output = render_denial_box(&pattern_match);
    log::debug!("Long command output:\n{}", output);
    // Verify box does not exceed terminal width
